	`userId` int NOT NULL,
	`vote` enum('for','against') NOT NULL,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `publicVotes_id` PRIMARY KEY(`id`)
);
ALTER TABLE `decisions` ADD `budget` decimal(12,2);
ALTER TABLE `decisions` ADD `publicVotingStartsAt` timestamp;
ALTER TABLE `decisions` ADD `publicVotingEndsAt` timestamp;
ALTER TABLE `decisions` ADD `publicVotesFor` int DEFAULT 0;
ALTER TABLE `decisions` ADD `publicVotesAgainst` int DEFAULT 0;

